SELECT underlying_asset, COUNT(contract_id) AS contract_count
FROM futures_contracts
GROUP BY underlying_asset;

SELECT name
FROM futures_contracts
WHERE contract_type = 'futures';

SELECT AVG(close_price) AS overall_avg_close
FROM trade_data
WHERE trade_date BETWEEN '2017-06-01' AND '2017-06-30';

SELECT name
FROM futures_contracts
WHERE contract_id = 1;

SELECT SUM(total_volume) AS total_volume_traded
FROM trade_data
WHERE trade_date = '2017-06-27';
